     2→import { siteConfig } from '../../site.config';
     3→import { getPostUrl } from './urls';
     4→
     5→export interface FeedItem {
     6→  title: string;
     7→  url: string;
     8→  date: Date;
     9→  excerpt: string;
    10→  content: string;
    11→  tags: string[];
    12→  authors?: string[];
    13→}
    14→
    15→export function getFeedItems(): FeedItem[] {
    16→  const { maxItems, includeFlows } = siteConfig.feed;
    17→  const baseUrl = siteConfig.baseUrl.replace(/\/+$/, '');
    18→
    19→  const postItems: FeedItem[] = getAllPosts().map((post) => ({
    20→    title: post.title,
    21→    url: `${baseUrl}${getPostUrl(post)}`,
    22→    date: new Date(post.date),
    23→    excerpt: post.excerpt,
    24→    content: post.content,
    25→    tags: post.tags || [],
    26→    authors: post.authors,
    27→  }));
    28→
    29→  let items: FeedItem[] = postItems;
    30→
    31→  if (includeFlows) {
    32→    const flowItems: FeedItem[] = getAllFlows().map((flow) => ({
    33→      title: flow.title,
    34→      url: `${baseUrl}/flows/${flow.slug}`,
    35→      date: new Date(flow.date),
    36→      excerpt: flow.excerpt,
    37→      content: flow.content,
    38→      tags: flow.tags || [],
    39→    }));
    40→    items = [...postItems, ...flowItems].sort((a, b) => b.date.getTime() - a.date.getTime());
    41→  }
    42→
    43→  return maxItems > 0 ? items.slice(0, maxItems) : items;
    44→}
