     1→/**
     2→ * Generate public/knowledge-graph.json for the Knowledge Graph visualization.
     3→ *
     4→ * Nodes: all posts, all notes, and flows that appear as wikilink source/target.
     5→ * Edges: wikilink edges (from backlink index) + series membership edges.
     6→ *
     7→ * Run: NODE_ENV=production bun scripts/generate-knowledge-graph.ts
     8→ */
     9→
    10→import fs from 'fs';
    11→import path from 'path';
    12→import { getAllPosts, getAllNotes, getAllFlows, getSeriesData } from '../src/lib/markdown';
    13→
    14→interface GraphNode {
    15→  id: string;
    16→  title: string;
    17→  type: 'post' | 'note' | 'flow' | 'series';
    18→  url: string;
    19→  connections: number;
    20→}
    21→
    22→interface GraphEdge {
    23→  source: string;
    24→  target: string;
    25→  type: 'wikilink' | 'series';
    26→}
    27→
    28→function extractWikilinks(content: string): string[] {
    29→  const slugs: string[] = [];
    30→  const re = /\[\[([^\]|]+?)(?:\|[^\]]+?)?\]\]/g;
    31→  let match;
    32→  while ((match = re.exec(content)) !== null) {
    33→    slugs.push(match[1].trim());
    34→  }
    35→  return slugs;
    36→}
    37→
    38→async function main() {
    39→  console.log('Generating knowledge graph…');
    40→
    41→  const posts = getAllPosts();
    42→  const notes = getAllNotes();
    43→  const flows = getAllFlows();
    44→
    45→  // Build id→node map
    46→  const nodeMap = new Map<string, GraphNode>();
    47→  const edges: GraphEdge[] = [];
    48→
    49→  // Add all posts and notes
    50→  for (const post of posts) {
    51→    nodeMap.set(post.slug, { id: post.slug, title: post.title, type: 'post', url: `/posts/${post.slug}`, connections: 0 });
    52→  }
    53→  for (const note of notes) {
    54→    nodeMap.set(note.slug, { id: note.slug, title: note.title, type: 'note', url: `/notes/${note.slug}`, connections: 0 });
    55→  }
    56→
    57→  // Track which flows appear in wikilinks (to avoid including ALL flows)
    58→  const linkedFlowSlugs = new Set<string>();
    59→
    60→  // Scan all content for wikilinks
    61→  const allContent: Array<{ slug: string; title: string; type: 'post' | 'note' | 'flow'; content: string; url: string }> = [
    62→    ...posts.map(p => ({ slug: p.slug, title: p.title, type: 'post' as const, content: p.content, url: `/posts/${p.slug}` })),
    63→    ...notes.map(n => ({ slug: n.slug, title: n.title, type: 'note' as const, content: n.content, url: `/notes/${n.slug}` })),
    64→    ...flows.map(f => ({ slug: f.slug, title: f.title, type: 'flow' as const, content: f.content, url: `/flows/${f.slug}` })),
    65→  ];
    66→
    67→  // Build wikilink edges (deduplicate per source document)
    68→  for (const item of allContent) {
    69→    const targets = extractWikilinks(item.content);
    70→    const seenTargets = new Set<string>();
    71→    for (const target of targets) {
    72→      if (target === item.slug) continue; // skip self
    73→      if (seenTargets.has(target)) continue; // skip duplicate within this doc
    74→      seenTargets.add(target);
    75→      edges.push({ source: item.slug, target, type: 'wikilink' });
    76→
    77→      // Ensure source exists in nodeMap
    78→      if (!nodeMap.has(item.slug)) {
    79→        nodeMap.set(item.slug, { id: item.slug, title: item.title, type: item.type, url: item.url, connections: 0 });
    80→        if (item.type === 'flow') linkedFlowSlugs.add(item.slug);
    81→      }
    82→      // Track referenced flows
    83→      const targetFlow = flows.find(f => f.slug === target);
    84→      if (targetFlow) {
    85→        linkedFlowSlugs.add(target);
    86→        if (!nodeMap.has(target)) {
    87→          nodeMap.set(target, { id: target, title: targetFlow.title, type: 'flow', url: `/flows/${target}`, connections: 0 });
    88→        }
    89→      }
    90→    }
    91→  }
    92→
    93→  // Add series nodes + series membership edges
    94→  const seriesSlugsSet = new Set<string>();
    95→  for (const post of posts) {
    96→    if (post.series) seriesSlugsSet.add(post.series);
    97→  }
    98→
    99→  for (const seriesSlug of seriesSlugsSet) {
   100→    const seriesData = getSeriesData(seriesSlug);
   101→    const seriesId = `series:${seriesSlug}`;
   102→    nodeMap.set(seriesId, {
   103→      id: seriesId,
   104→      title: seriesData?.title || seriesSlug,
   105→      type: 'series',
   106→      url: `/series/${seriesSlug}`,
   107→      connections: 0,
   108→    });
   109→    // Add edges from series to each post
   110→    for (const post of posts) {
   111→      if (post.series === seriesSlug) {
   112→        edges.push({ source: seriesId, target: post.slug, type: 'series' });
   113→      }
   114→    }
   115→  }
   116→
   117→  // Compute connection counts
   118→  for (const edge of edges) {
   119→    const src = nodeMap.get(edge.source);
   120→    if (src) src.connections++;
   121→    const tgt = nodeMap.get(edge.target);
   122→    if (tgt) tgt.connections++;
   123→  }
   124→
   125→  // Filter out nodes with no edges (isolated) to keep graph clean
   126→  const connectedIds = new Set<string>();
   127→  for (const edge of edges) {
   128→    connectedIds.add(edge.source);
   129→    connectedIds.add(edge.target);
   130→  }
   131→
   132→  // Always include all notes and posts (they are the knowledge base)
   133→  const nodes = Array.from(nodeMap.values()).filter(n =>
   134→    n.type === 'note' || n.type === 'post' || n.type === 'series' || connectedIds.has(n.id)
   135→  );
   136→
   137→  // Filter edges to only include those with both source and target in nodes
   138→  const validIds = new Set(nodes.map(n => n.id));
   139→  const validEdges = edges.filter(e => validIds.has(e.source) && validIds.has(e.target));
   140→
   141→  // Recompute connection counts from validEdges only (pre-filter counts were inflated)
   142→  const connectionCounts = new Map<string, number>();
   143→  for (const edge of validEdges) {
   144→    connectionCounts.set(edge.source, (connectionCounts.get(edge.source) ?? 0) + 1);
   145→    connectionCounts.set(edge.target, (connectionCounts.get(edge.target) ?? 0) + 1);
   146→  }
   147→  for (const node of nodes) {
   148→    node.connections = connectionCounts.get(node.id) ?? 0;
   149→  }
   150→
   151→  const graphData = { nodes, edges: validEdges };
   152→
   153→  const outputPath = path.join(process.cwd(), 'public', 'knowledge-graph.json');
   154→  fs.writeFileSync(outputPath, JSON.stringify(graphData, null, 2));
   155→
   156→  console.log(`✓ Written ${nodes.length} nodes, ${validEdges.length} edges → ${outputPath}`);
   157→}
   158→
   159→main().catch(err => {
   160→  console.error('Error generating knowledge graph:', err);
   161→  process.exit(1);
   162→});
