    10→
    11→export default function FlowHubTabs({ subtitle }: FlowHubTabsProps) {
    12→  const pathname = usePathname();
    13→  const { t } = useLanguage();
    14→
    15→  // Normalize: strip trailing slash added by next.config trailingSlash:true
    16→  const path = pathname.endsWith('/') ? pathname.slice(0, -1) : pathname;
    17→
    18→  const isFlowsActive = path === '/flows' || path.startsWith('/flows/page');
    19→  const isNotesActive = path === '/notes' || path.startsWith('/notes/page');
    20→  const isGraphActive = path.startsWith('/graph');
    21→
    22→  const tabs = [
    23→    { href: '/flows', label: t('tab_daily_flow'), active: isFlowsActive },
    24→    { href: '/notes', label: t('notes'), active: isNotesActive },
    25→    { href: '/graph', label: t('tab_graph'), active: isGraphActive },
    26→  ];
    27→
    28→  return (
    29→    <div className="mb-10">
    30→      <div className="flex items-end gap-8 border-b border-muted/20">
    31→        {tabs.map(tab => (
    32→          <Link
    33→            key={tab.href}
    34→            href={tab.href}
    35→            className={`pb-3 text-3xl font-bold no-underline border-b-2 -mb-px transition-colors ${
    36→              tab.active
    37→                ? 'border-accent text-heading'
    38→                : 'border-transparent text-muted/30 hover:text-muted/60'
    39→            }`}
    40→          >
    41→            {tab.label}
    42→          </Link>
    43→        ))}
    44→      </div>
    45→      {subtitle && (
    46→        <p className="mt-3 text-sm text-muted">{subtitle}</p>
    47→      )}
    48→    </div>
    49→  );
    50→}
